mapper.select:
SELECT
    TO_CHAR(collected_at, 'HH24:MI') as time_label,
    COALESCE(
        EXTRACT(EPOCH FROM (collected_at - LAG(collected_at) OVER (ORDER BY collected_at))) / 60.0,
        0.0
    ) as interval_minutes
FROM checkpoint_agg
WHERE instance_id = #{instanceId}
  AND collected_at BETWEEN #{startTime} AND #{endTime}
ORDER BY collected_at

SELECT checkpoint_raw_id as id, TO_CHAR(collected_at, 'YYYY-MM-DD HH24:MI:SS') as timestamp, checkpoint_type as type, COALESCE(checkpoint_write_time, 0.0) as writeTime, COALESCE(checkpoint_sync_time, 0.0) as syncTime, COALESCE(checkpoint_write_time + checkpoint_sync_time, 0.0) as totalTime, CONCAT(ROUND(wal_bytes / 1048576.0, 2), ' MB') as walGenerated, COALESCE(wal_files_added, 0) as walFilesAdded, COALESCE(wal_files_removed, 0) as walFilesRemoved, CONCAT(ROUND(checkpoint_distance / 1048576.0, 2), ' MB') as checkpointDistance, COALESCE(buffers_checkpoint, 0) as buffersWritten, COALESCE(buffers_backend, 0) as buffersBackend, COALESCE(avg_buffers_per_sec, 0.0) as avgBuffersPerSec, CASE WHEN checkpoint_write_time + checkpoint_sync_time > 30 THEN '위험' WHEN checkpoint_write_time + checkpoint_sync_time > 15 THEN '주의' ELSE '정상' END as status FROM checkpoint_raw WHERE instance_id = #{instanceId} AND collected_at BETWEEN #{startTime} AND #{endTime}
AND CASE WHEN checkpoint_write_time + checkpoint_sync_time > 30 THEN '위험' WHEN checkpoint_write_time + checkpoint_sync_time > 15 THEN '주의' ELSE '정상' END IN
#{status}
ORDER BY collected_at DESC
